    yield* fromPromise(() =>
      writeTicket(projectPath, {
        ...ticket,
        markdown: patch.markdown ?? ticket.markdown,
        frontMatter: {
          ...ticket.frontMatter,
          codexThreadId: patch.codexThreadId !== undefined ? patch.codexThreadId : ticket.frontMatter.codexThreadId,
