  background: transparent;
  color: var(--relay-text);
}

.project-main {
  min-width: 0;
  display: grid;
  gap: 4px;
}

.project-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-weight: 560;
  color: rgb(255 255 255 / 82%);
}

.project-path {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.project-badges {
  color: var(--relay-warning);
  display: flex;
  align-items: center;
  gap: var(--relay-space-1);
  flex-shrink: 0;
}

.project-main .git-metadata {
