  max-width: 100%;
  max-height: 0;
  opacity: 0;
  transform: translateY(-2px);
  transition:
    max-height 180ms var(--relay-ease),
    opacity 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

.project-row-shell:hover .project-main .git-metadata,
.project-row-shell:focus-within .project-main .git-metadata,
.project-row-shell.selected .project-main .git-metadata {
