}

.topbar h1 {
  max-width: min(56vw, 720px);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: 18px;
  font-weight: 560;
  line-height: 1.2;
  letter-spacing: 0;
}

}

.topbar p {
  max-width: min(58vw, 760px);
  margin-top: 4px;
