  text-align: center;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 3.5%), transparent),
    rgb(255 255 255 / 2.5%);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
  transition:
    background-color 180ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease);
}

.empty-column span {
  color: var(--relay-text-muted);
