  transition: none;
}

.card-open:hover {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:active {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:focus-visible {
  background: transparent;
  box-shadow: none;
}

.card-title {
  margin-bottom: 8px;
  color: var(--relay-text);
  font-weight: 560;
  line-height: 1.32;
}

.card-excerpt {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 4;
  margin: 0;
  color: rgb(255 255 255 / 66%);
  font-size: var(--relay-text-md);
  line-height: 1.5;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 12px;
  opacity: 0.82;
}

.priority,
.run-pill,
.ticket-type-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

}

.git-metadata.compact {
