  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  font-size: var(--relay-text-md);
}

.ticket-update-error.warning {
  background: rgb(251 191 36 / 12%);
  color: #fbbf24;
}

.detail-markdown {
  min-height: 360px;
}

.agent-activity-panel {
  margin-top: var(--relay-space-4);
  overflow: hidden;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4%), transparent),
    var(--relay-surface);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

  .modal-grid,
  .create-fields,
  .two-fields {
    grid-template-columns: 1fr;
  }

  .status-rail {
    right: 10px;
    bottom: 10px;
    left: 10px;
  }

  .codex-status {
    width: 100%;
  }
}

@media (max-width: 520px) {
  button {
    padding-inline: 10px;
  }

  .topbar-actions,
  .modal-footer,
  .detail-actions,
  .ticket-update-actions,
  .agent-panel-actions,
  .danger-row {
    display: grid;
    grid-template-columns: 1fr;
  }

  .topbar-actions button,
  .modal-footer button,
  .detail-actions button,
  .ticket-update-actions button,
  .agent-panel-actions button,
  .danger-row button {
    width: 100%;
  }

  .agent-metrics,
  .agent-recent-row,
  .agent-log-item,
  .link-existing-row,
  .subticket-item,
  .subticket-row {
    grid-template-columns: 1fr;
  }

  .agent-log-meta {
    border-right: 0;
    border-bottom: 0;
    box-shadow: inset 0 -1px 0 rgb(255 255 255 / 5%);
  }
}

